public static boolean validateHeader(Common _record)
{
    boolean isValidHeader = true;

    if (ETGACFParameters::find().EnableMandatoryFields == NoYes::Yes)
    {
        switch (_record.TableId)
        {
            case tableNum(ETG_SalesAgreementHeader):
                isValidHeader = ETGSalesAgreementMandatoryValidation::validateETG_SalesAgreementHeader(_record as ETG_SalesAgreementHeader);
                break;

            case tableNum(AgreementHeaderDefault):
                isValidHeader = ETGSalesAgreementMandatoryValidation::validateAgreementHeaderDefault(_record as AgreementHeaderDefault);
                break;

            case tableNum(SalesAgreementHeaderDefault):
                isValidHeader = ETGSalesAgreementMandatoryValidation::validateSalesAgreementHeaderDefault(_record as SalesAgreementHeaderDefault);
                break;

            case tableNum(SalesAgreementHeader):
                isValidHeader = ETGSalesAgreementMandatoryValidation::validateSalesAgreementHeader(_record as SalesAgreementHeader);
                break;

            default:
                isValidHeader = true;
        }
    }

    return isValidHeader;
}

public static boolean validateLine(Common _record)
{
    boolean isValidLine = true;

    if (ETGACFParameters::find().EnableMandatoryFields == NoYes::Yes)
    {
        switch (_record.TableId)
        {
            case tableNum(AgreementLine):       
                isValidLine = ETGSalesAgreementMandatoryValidation::validateALine(_record as AgreementLine);
                break;

            case tableNum(InventDim):
                isValidLine = ETGSalesAgreementMandatoryValidation::validateInventDim(_record as InventDim);
                break;

            case tableNum(AgreementLineQuantityCommitment):
                isValidLine = ETGSalesAgreementMandatoryValidation::validateAgrLineQtyCommitment(_record as AgreementLineQuantityCommitment);
                break;

            default:
                isValidLine = true;
        }
    }

    return isValidLine;
}

// Header DS tables Validation
private static boolean validateETG_SalesAgreementHeader(ETG_SalesAgreementHeader _record)
{
    boolean ret = true;

    if (!_record.FromDatePort)
    {
        ret = checkFailed("From Date is mandatory.");
    }

    if (!_record.ToDatePort)
    {
        ret = checkFailed("To Date is mandatory.");
    }

    if (!_record.PortOfLoading)
    {
        ret = checkFailed("Port/Place of loading is mandatory.");
    }

    if (!_record.PortOfDischarge)
    {
        ret = checkFailed("Port/Place of discharge is mandatory.");
    }

    if (!_record.BuyerAccountNum)
    {
        ret = checkFailed("Buyer account is mandatory.");
    }

    if (!_record.SellerAccountNum)
    {
        ret = checkFailed("Seller account is mandatory.");
    }

    return ret;
}

private static boolean validateAgreementHeaderDefault(AgreementHeaderDefault _record)
{
    boolean ret = true;

    if (!_record.DeliveryMode)
    {
        ret = checkFailed("Delivery mode is mandatory.");
    }

    if (!_record.DeliveryTerm)
    {
        ret = checkFailed("Delivery terms is mandatory.");
    }

    if (!_record.PaymentTerms)
    {
        ret = checkFailed("Terms of payment is mandatory.");
    }

    return ret;
}

private static boolean validateSalesAgreementHeaderDefault(SalesAgreementHeaderDefault _record)
{
    boolean ret = true;

    if (!_record.CustomerMethodOfPayment)
    {
        ret = checkFailed("Method of payment is mandatory.");
    }

    return ret;
}

private static boolean validateSalesAgreementHeader(SalesAgreementHeader _record)
{
    boolean ret = true;

    if (!_record.ETGReasonCode && (_record.AgreementState == AgreementState::ETGForceClosed || _record.AgreementState == AgreementState::ETGTerminated))
    {
        ret = checkFailed("Reason code is mandatory.");
    }

    return ret;
}

// Line DS tables Validation   
private static boolean validateALine(AgreementLine _record)
{
    boolean ret = true;

    if (!_record.ItemId)
    {
        ret =  checkFailed("Item number is mandatory.");
    }

    if (!_record.ETGFinalPlaceOfDelivery)
    {
       ret =  checkFailed("Final place of delivery is mandatory.");
    }

    return ret;
}

private static boolean validateInventDim(InventDim _record)
{
    boolean ret = true;

    if (!_record.ConfigId)
    {
        ret = checkFailed("Grade is mandatory.");
    }

    if (!_record.InventSizeId)
    {
        ret =checkFailed("Size is mandatory.");
    }

    if (!_record.InventColorId)
    {
        ret =checkFailed("Origin is mandatory.");
    }

    if (!_record.InventStyleId)
    {
        ret =checkFailed("Brand is mandatory.");
    }

    if (!_record.InventSiteId)
    {
        ret =checkFailed("Site is mandatory.");
    }

    if (!_record.InventLocationId)
    {
        ret =checkFailed("Warehouse is mandatory.");
    }

    if (!_record.wMSLocationId)
    {
        ret= checkFailed("Location is mandatory.");
    }

    return ret;
}

private static boolean validateAgrLineQtyCommitment(AgreementLineQuantityCommitment _record)
{
    boolean ret = true;

    if (!_record.CommitedQuantity)
    {
        ret= checkFailed("Quantity is mandatory");
    }

    if (!_record.PricePerUnit)
    {
        ret= checkFailed("Unit price is mandatory");
    }

    return ret;
}

public static boolean validateFormHeaders(FormRun _formRun)
{
    boolean ret = true;

    FormDataSource formDS1 = _formRun.dataSource(formDataSourceStr(SalesAgreement, ETG_SalesAgreementHeader));
    if (formDS1 && formDS1.cursor())
        ret = ret && ETGSalesAgreementMandatoryValidation::validateHeader(formDS1.cursor());


    FormDataSource formDS2 = _formRun.dataSource(formDataSourceStr(SalesAgreement, AgreementHeaderDefault));
    if (formDS2 && formDS2.cursor())
        ret = ret && ETGSalesAgreementMandatoryValidation::validateHeader(formDS2.cursor());

    FormDataSource formDS3 = _formRun.dataSource(formDataSourceStr(SalesAgreement, SalesAgreementHeaderDefault));
    if (formDS3 && formDS3.cursor())
        ret = ret && ETGSalesAgreementMandatoryValidation::validateHeader(formDS3.cursor());

    FormDataSource formDS4 = _formRun.dataSource(formDataSourceStr(SalesAgreement, SalesAgreementHeader));
    if (formDS4 && formDS4.cursor())
        ret = ret && ETGSalesAgreementMandatoryValidation::validateHeader(formDS4.cursor());

    return ret;
}

public static boolean validateFormLines(FormRun _formRun)
{
    boolean ret = true;

    FormDataSource formDS1 = _formRun.dataSource(formDataSourceStr(SalesAgreement, ALine));
    if (formDS1 && formDS1.cursor())
        ret = ret && ETGSalesAgreementMandatoryValidation::validateLine(formDS1.cursor());


    FormDataSource formDS2 = _formRun.dataSource(formDataSourceStr(SalesAgreement, InventDim));
    if (formDS2 && formDS2.cursor())
        ret = ret && ETGSalesAgreementMandatoryValidation::validateLine(formDS2.cursor());

    FormDataSource formDS3 = _formRun.dataSource(formDataSourceStr(SalesAgreement, ALine_AgreementLineQuantityCommitment));
    if (formDS3 && formDS3.cursor())
        ret = ret && ETGSalesAgreementMandatoryValidation::validateLine(formDS3.cursor());

    return ret;
}
